column12:
{
  "note": "Fish sauce is a common ingredient in Korean cuisine, but it may not be easily found in all North American stores.",
  "alts": [
    {"name_en": "Nama shoyu", "match": "Similar", "desc": "A Japanese fermented soybean paste that can provide a similar umami flavor, often used in Korean cooking.", "where": "International or Asian food section"},
    {"name_en": "Korean chili paste (gochujang) with anchovy or fish stock", "match": "Different but works", "desc": "While not a direct substitute, combining gochujang with anchovy or fish stock can replicate the savory, umami flavor of fish sauce in Korean dishes.", "where": "International or Asian food section"},
    {"name_en": "Soy sauce with kombu dashi", "match": "Similar", "desc": "Mixing soy sauce with kombu dashi (a Japanese seaweed stock) can create a similar savory flavor profile to fish sauce, suitable for Korean recipes.", "where": "International or Asian food section"},
    {"name_en": "Doenjang (Korean fermented soybean paste)", "match": "Similar", "desc": "While thicker and with a stronger flavor, doenjang can be used diluted as a substitute for fish sauce in some Korean recipes.", "where": "International or Asian food section"}
  ]
}

column18:
{
    "note": "Fish sauce is essential for Korean cooking's umami depth.",
    "alts": [
        {
